class Solution:
	def binary_exponentiation(self, base: int, exp: int) -> int:
		if exp == 0:
			return 1
		elif exp % 2 == 0:
			intermediate = binary_exponentiation(base, exp // 2)
			return intermediate * intermediate
		else:
			intermediate = binary_exponentiation(base, (exp - 1) // 2)
			return base * intermediate * intermediate

if __name__ == '__main__':
