class Solution {
public:
	int binaryExponentiation(int base, int exp) {
		if (exp == 0) return 1;
		elif (exp % 2 == 0) {
			int intermediate = binaryExponentiation(base, exp / 2);
			return intermediate * intermediate;
		}
		else {
			int intermediate = binaryExponentiation(base, (exp - 1) / 2);
			return base * intermediate * intermediate;
		}
	}
};
